 }
+/// Return true if we can determine V1 != V2 from a dominating comparison.
+static bool isKnownNonEqualFromDominatingCondition(const Value *V1,
+                                                   const Value *V2,
+                                                   const Instruction *CtxI,
+                                                   const DominatorTree *DT) {
+  if (!CtxI || !DT)
+    return false;
+
+  // Look through uses of V1 for icmp ne V1, V2 or icmp ne V2, V1
+  // or icmp eq V1, V2 or icmp eq V2, V1
+  for (const Use &U : V1->uses()) {
+    const Instruction *UI = cast<Instruction>(U.getUser());
+
+    // Check for icmp pred V1, V2 or icmp pred V2, V1
+    Value *LHS, *RHS;
+    CmpPredicate Pred;
+    if (!match(UI, m_c_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
+      continue;
+
+    // Check if this is comparing V1 and V2
+    bool IsMatch = (LHS == V1 && RHS == V2) || (LHS == V2 && RHS == V1);
+    if (!IsMatch)
+      continue;
+
+    bool NonEqualIfTrue;
+    if (Pred == CmpInst::ICMP_NE)
+      NonEqualIfTrue = true;
+    else if (Pred == CmpInst::ICMP_EQ)
+      NonEqualIfTrue = false;
+    else
+      continue;
+
+    // Walk through users to find branches
+    SmallVector<const User *, 4> WorkList;
+    SmallPtrSet<const User *, 4> Visited;
+    for (const auto *CmpU : UI->users()) {
+      if (Visited.insert(CmpU).second)
+        WorkList.push_back(CmpU);

-/// Return true if it is known that V1 != V2.
+      while (!WorkList.empty()) {
+        auto *Curr = WorkList.pop_back_val();
+
+        // Propagate through AND (all conditions must be true)
+        if (match(Curr, m_LogicalAnd(m_Value(), m_Value()))) {
+          for (const auto *CurrU : Curr->users())
+            if (Visited.insert(CurrU).second)
+              WorkList.push_back(CurrU);
+          continue;
+        }
+
+        if (const BranchInst *BI = dyn_cast<BranchInst>(Curr)) {
+          if (!BI->isConditional())
+            continue;
+          // For icmp ne, true branch means V1 != V2
+          // For icmp eq, false branch means V1 != V2
+          BasicBlock *TargetSucc = BI->getSuccessor(NonEqualIfTrue ? 0 : 1);
+          BasicBlockEdge Edge(BI->getParent(), TargetSucc);
+          if (Edge.isSingleEdge() && DT->dominates(Edge, CtxI->getParent()))
+            return true;
+        } else if (isGuard(Curr) && DT->dominates(cast<Instruction>(Curr), CtxI)) {
+          return true;
+        }
+      }
+    }
+  }
+
+  return false;
+}
 static bool isKnownNonEqual(const Value *V1, const Value *V2,
                             const APInt &DemandedElts, unsigned Depth,
                             const SimplifyQuery &Q) {
@@ -3799,6 +3868,9 @@ static bool isKnownNonEqual(const Value *V1, const Value *V2,
   if (Depth >= MaxAnalysisRecursionDepth)
     return false;

+  // Check for dominating icmp ne V1, V2 branch condition
+  if (isKnownNonEqualFromDominatingCondition(V1, V2, Q.CxtI, Q.DT))
+    return true;
   // See if we can recurse through (exactly one of) our operands.  This
   // requires our operation be 1-to-1 and map every input value to exactly
   // one output value.  Such an operation is invertible.

